local cjson = require "cjson"

-- Secure XML parser implementation
local function create_secure_xml_parser()
    local parser = {}
    
    -- Whitelist of allowed entity references
    local ALLOWED_ENTITIES = {
        ["&lt;"] = "<",
        ["&gt;"] = ">",
        ["&amp;"] = "&",
        ["&quot;"] = '"',
        ["&apos;"] = "'"
    }
    
    -- Security limits
    local MAX_DEPTH = 50
    local MAX_ATTRIBUTES = 100
    local MAX_ENTITY_EXPANSIONS = 1000
    local MAX_ENTITY_EXPANSION_LENGTH = 10000
    local MAX_ELEMENT_NAME_LENGTH = 256
    local MAX_ATTRIBUTE_NAME_LENGTH = 256
    local MAX_TEXT_LENGTH = 1000000
    
    local entity_expansion_count = 0
    local total_expansion_length = 0
    
    -- Decode only whitelisted entity references
    local function decode_entities(text)
        if not text then return text end
        
        local result = text
        local changed = true
        
        while changed do
            changed = false
            entity_expansion_count = entity_expansion_count + 1
            
            if entity_expansion_count > MAX_ENTITY_EXPANSIONS then
                error("Entity expansion limit exceeded - possible billion laughs attack")
            end
            
            for entity, replacement in pairs(ALLOWED_ENTITIES) do
                local new_result = result:gsub(entity, replacement)
                if new_result ~= result then
                    changed = true
                    result = new_result
                    total_expansion_length = total_expansion_length + #result
                    
                    if total_expansion_length > MAX_ENTITY_EXPANSION_LENGTH then
                        error("Entity expansion length limit exceeded")
                    end
                end
            end
        end
        
        -- Check for any remaining entity references (not allowed)
        if result:match("&[%w]+;") then
            error("Disallowed entity reference found")
        end
        
        -- Check for DOCTYPE or ENTITY declarations
        if result:match("<!%s*DOCTYPE") or result:match("<!%s*ENTITY") then
            error("DOCTYPE and ENTITY declarations are not allowed")
        end
        
        return result
    end
    
    -- Validate element/attribute names
    local function validate_name(name, max_length)
        if not name or #name == 0 then
            error("Empty name not allowed")
        end
        if #name > max_length then
            error("Name too long: " .. #name)
        end
        -- Only allow alphanumeric, underscore, hyphen, colon, and period
        if not name:match("^[%w_:.-]+$") then
            error("Invalid characters in name: " .. name)
        end
    end
    
    -- Parse XML string into table structure
    function parser.parse(xml_string)
        if not xml_string or #xml_string == 0 then
            error("Empty XML string")
        end
        
        if #xml_string > MAX_TEXT_LENGTH then
            error("XML document too large")
        end
        
        -- Reset counters
        entity_expansion_count = 0
        total_expansion_length = 0
        
        -- Check for dangerous patterns before parsing
        if xml_string:match("<!%s*DOCTYPE") then
            error("DOCTYPE declarations are not allowed")
        end
        if xml_string:match("<!%s*ENTITY") then
            error("ENTITY declarations are not allowed")
        end
        if xml_string:match("<!%[CDATA%[") and xml_string:match("<!%[CDATA%[.*<!%[CDATA%[") then
            error("Nested CDATA sections not allowed")
        end
        
        local stack = {}
        local top = {name = "root", children = {}, attrs = {}}
        local current = top
        local depth = 0
        
        local i = 1
        while i <= #xml_string do
            local char = xml_string:sub(i, i)
            
            -- Skip whitespace between tags
            if char:match("%s") and xml_string:sub(i):match("^%s*<") then
                i = i + 1
            -- Handle opening tag
            elseif char == "<" then
                local next_char = xml_string:sub(i + 1, i + 1)
                
                -- Closing tag
                if next_char == "/" then
                    local tag_end = xml_string:find(">", i + 2)
                    if not tag_end then
                        error("Malformed closing tag")
                    end
                    
                    local tag_name = xml_string:sub(i + 2, tag_end - 1):match("^%s*(.-)%s*$")
                    validate_name(tag_name, MAX_ELEMENT_NAME_LENGTH)
                    
                    if current.name ~= tag_name then
                        error("Mismatched closing tag: expected " .. current.name .. ", got " .. tag_name)
                    end
                    
                    current = table.remove(stack)
                    if not current then
                        error("Unexpected closing tag")
                    end
                    depth = depth - 1
                    i = tag_end + 1
                    
                -- Comment
                elseif xml_string:sub(i, i + 3) == "<!--" then
                    local comment_end = xml_string:find("-->", i + 4)
                    if not comment_end then
                        error("Unclosed comment")
                    end
                    i = comment_end + 3
                    
                -- CDATA
                elseif xml_string:sub(i, i + 8) == "<![CDATA[" then
                    local cdata_end = xml_string:find("]]>", i + 9)
                    if not cdata_end then
                        error("Unclosed CDATA section")
                    end
                    local cdata_content = xml_string:sub(i + 9, cdata_end - 1)
                    table.insert(current.children, {text = cdata_content})
                    i = cdata_end + 3
                    
                -- Processing instruction or XML declaration
                elseif next_char == "?" then
                    local pi_end = xml_string:find("?>", i + 2)
                    if not pi_end then
                        error("Unclosed processing instruction")
                    end
                    i = pi_end + 2
                    
                -- Opening tag
                else
                    depth = depth + 1
                    if depth > MAX_DEPTH then
                        error("Maximum nesting depth exceeded")
                    end
                    
                    local tag_end = xml_string:find("[/>]", i + 1)
                    if not tag_end then
                        error("Malformed opening tag")
                    end
                    
                    local tag_content = xml_string:sub(i + 1, tag_end - 1)
                    local self_closing = xml_string:sub(tag_end, tag_end + 1) == "/>"
                    
                    -- Parse tag name and attributes
                    local tag_name = tag_content:match("^%s*([^%s/>]+)")
                    if not tag_name then
                        error("Invalid tag name")
                    end
                    validate_name(tag_name, MAX_ELEMENT_NAME_LENGTH)
                    
                    local element = {name = tag_name, children = {}, attrs = {}}
                    
                    -- Parse attributes
                    local attr_count = 0
                    for attr_name, attr_value in tag_content:gmatch('([%w_:.-]+)%s*=%s*["\']([^"\']*)["\']') do
                        attr_count = attr_count + 1
                        if attr_count > MAX_ATTRIBUTES then
                            error("Too many attributes")
                        end
                        validate_name(attr_name, MAX_ATTRIBUTE_NAME_LENGTH)
                        element.attrs[attr_name] = decode_entities(attr_value)
                    end
                    
                    table.insert(current.children, element)
                    
                    if not self_closing then
                        table.insert(stack, current)
                        current = element
                    else
                        depth = depth - 1
                    end
                    
                    i = tag_end + (self_closing and 2 or 1)
                end
            -- Text content
            else
                local text_end = xml_string:find("<", i)
                if not text_end then
                    text_end = #xml_string + 1
                end
                
                local text = xml_string:sub(i, text_end - 1)
                local trimmed = text:match("^%s*(.-)%s*$")
                
                if trimmed and #trimmed > 0 then
                    table.insert(current.children, {text = decode_entities(trimmed)})
                end
                
                i = text_end
            end
        end
        
        if #stack > 0 then
            error("Unclosed tags remaining")
        end
        
        return top.children[1] or top
    end
    
    -- Helper function to find element by name
    function parser.find_element(node, name)
        if not node or not node.children then
            return nil
        end
        
        for _, child in ipairs(node.children) do
            if child.name == name then
                return child
            end
        end
        return nil
    end
    
    -- Helper function to get element text
    function parser.get_text(node)
        if not node then
            return nil
        end
        
        if node.text then
            return node.text
        end
        
        if node.children then
            for _, child in ipairs(node.children) do
                if child.text then
                    return child.text
                end
            end
        end
        
        return nil
    end
    
    -- Helper function to get all elements by name
    function parser.find_all_elements(node, name)
        local results = {}
        if not node or not node.children then
            return results
        end
        
        for _, child in ipairs(node.children) do
            if child.name == name then
                table.insert(results, child)
            end
        end
        return results
    end
    
    return parser
end

-- Main request handler
local function handle_soap_request()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "No request body"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    -- Validate Content-Type
    local content_type = ngx.var.content_type or ""
    if not content_type:match("text/xml") and not content_type:match("application/soap%+xml") and not content_type:match("application/xml") then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "Invalid Content-Type. Expected text/xml or application/soap+xml"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local parser = create_secure_xml_parser()
    local success, result = pcall(parser.parse, body)
    
    if not success then
        ngx.log(ngx.ERR, "XML parsing error: ", result)
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "Invalid XML: " .. tostring(result)}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    -- Extract SOAP envelope
    local envelope = result
    if envelope.name ~= "Envelope" and envelope.name ~= "soap:Envelope" and envelope.name ~= "soapenv:Envelope" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "Invalid SOAP envelope"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    -- Extract SOAP body
    local body_element = parser.find_element(envelope, "Body") or 
                        parser.find_element(envelope, "soap:Body") or
                        parser.find_element(envelope, "soapenv:Body")
    
    if not body_element then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "SOAP Body not found"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    -- Extract operation (first child of Body)
    local operation = body_element.children and body_element.children[1]
    if not operation then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "No operation found in SOAP Body"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    -- Extract parameters from operation
    local params = {}
    if operation.children then
        for _, param in ipairs(operation.children) do
            if param.name then
                params[param.name] = parser.get_text(param)
            end
        end
    end
    
    -- Store parsed data in ngx.ctx for downstream processing
    ngx.ctx.soap_operation = operation.name
    ngx.ctx.soap_params = params
    ngx.ctx.soap_envelope = envelope
    
    -- Example response
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode({
        success = true,
        operation = operation.name,
        parameters = params
    }))
end

